CODE_EXAMPLE:
// Before
String foundPerson(String[] people, String name) {
  for (int i = 0; i < people.length; i++) {
    if (people[i].equals(name)) {
      return "Found";
    }
  }
  return "Not found";
}

// After
String foundPerson(String[] people, String name) {
  List<String> candidates = Arrays.asList(people);
  if (candidates.contains(name)) {
    return "Found";
  }
  return "Not found";
}

UNIT_TEST_EXAMPLE:
@Test
public void testSubstituteAlgorithm() {
  String[] people = {"Alice", "Bob", "Charlie"};
  assertEquals("Found", foundPerson(people, "Bob"));
  assertEquals("Not found", foundPerson(people, "David"));
}
